const crypto = require('crypto');

const locationConfig = $('Fetch Locations With Dataset').first().json;
const leads = $('Fetch Qualified Leads').all();

function sha256(value) {
  if (value == null || value === '' || value === 'NULL') return null;
  const normalized = String(value).trim().toLowerCase();
  return crypto.createHash('sha256').update(normalized).digest('hex');
}

function normalizePhone(phone) {
  if (phone == null) return null;
  // Remove everything except digits
  const digits = String(phone).replace(/\D/g, '');
  return digits;
}

function splitName(fullName) {
  if (fullName == null) return { fn: null, ln: null };
  const parts = String(fullName).trim().split(/\s+/);
  const fn = parts[0] || null;
  const ln = parts.length > 1 ? parts.slice(1).join(' ') : null;
  return { fn, ln };
}

const userData = [];
for (const lead of leads) {
  const { lead_name, email, phone } = lead.json;
  const { fn, ln } = splitName(lead_name);
  const normalizedPhone = normalizePhone(phone);

  const entry = {};
  const hashedEmail = sha256(email);
  const hashedPhone = sha256(normalizedPhone);
  const hashedFn = sha256(fn);
  const hashedLn = sha256(ln);

  if (hashedEmail) entry.EMAIL = hashedEmail;
  if (hashedPhone) entry.PHONE = hashedPhone;
  if (hashedFn) entry.FN = hashedFn;
  if (hashedLn) entry.LN = hashedLn;

  if (Object.keys(entry).length > 0) {
    userData.push(entry);
  }
}

return [{
  json: {
    location_id: locationConfig.location_id,
    brand_name: locationConfig.brand_name,
    meta_ad_account_id: locationConfig.meta_ad_account_id,
    meta_access_token: locationConfig.meta_access_token,
    user_data: userData,
    lead_count: userData.length,
    audience_name: 'Leads Qualificados - ' + (locationConfig.brand_name || locationConfig.location_id)
  }
}];

